item.content:encoded:
[css.minify]
	@layer tokens, base, blocks, sections;
  [this_collection.include reset /]
	[this_collection.include classless /]
[/css.minify]

//**
 * Awesome CSS — Classless Base (Editorial Content) v0.1.0
 *
 * SCOPED: :where(.entry-content) → zero specificity.
 * Any block class wins automatically. No overrides needed.
 *
 * Makes Gutenberg editorial output (posts, pages) look great
 * with zero CSS classes. Custom blocks are never affected.
 **//

@layer base {

  //** ── Vertical Rhythm ─────────────────────────────────────────────────── **//

  :where(.entry-content) > * + * {
    margin-block-start: var(--awx-space-stack);
  }


  //** ── Headings ────────────────────────────────────────────────────────── **//

  :where(.entry-content) h1 {
    font-family: var(--awx-font-heading);
    font-size: var(--awx-font-size-6);
    font-weight: var(--awx-font-weight-bold);
    line-height: var(--awx-leading-tight);
    letter-spacing: var(--awx-tracking-tighter);
    color: hsl(var(--awx-color-text));
    margin-block-start: var(--awx-space-heading-above);
    margin-block-end: var(--awx-space-heading-below);
  }

  :where(.entry-content) h2 {
    font-family: var(--awx-font-heading);
    font-size: var(--awx-font-size-5);
    font-weight: var(--awx-font-weight-bold);
    line-height: var(--awx-leading-tight);
    letter-spacing: var(--awx-tracking-tight);
    color: hsl(var(--awx-color-text));
    margin-block-start: var(--awx-space-heading-above);
    margin-block-end: var(--awx-space-heading-below);
  }

  :where(.entry-content) h3 {
    font-family: var(--awx-font-heading);
    font-size: var(--awx-font-size-4);
    font-weight: var(--awx-font-weight-semibold);
    line-height: var(--awx-leading-snug);
    letter-spacing: var(--awx-tracking-tight);
    color: hsl(var(--awx-color-text));
    margin-block-start: var(--awx-space-heading-above);
    margin-block-end: var(--awx-space-heading-below);
  }

  :where(.entry-content) h4 {
    font-family: var(--awx-font-heading);
    font-size: var(--awx-font-size-3);
    font-weight: var(--awx-font-weight-semibold);
    line-height: var(--awx-leading-snug);
    color: hsl(var(--awx-color-text));
    margin-block-start: var(--awx-space-heading-above);
    margin-block-end: var(--awx-space-heading-below);
  }

  :where(.entry-content) h5 {
    font-family: var(--awx-font-heading);
    font-size: var(--awx-font-size-2);
    font-weight: var(--awx-font-weight-semibold);
    line-height: var(--awx-leading-snug);
    color: hsl(var(--awx-color-text));
    margin-block-start: var(--awx-space-heading-above);
    margin-block-end: var(--awx-space-heading-below);
  }

  :where(.entry-content) h6 {
    font-family: var(--awx-font-heading);
    font-size: var(--awx-font-size-1);
    font-weight: var(--awx-font-weight-semibold);
    line-height: var(--awx-leading-normal);
    letter-spacing: var(--awx-tracking-wide);
    text-transform: uppercase;
    color: hsl(var(--awx-color-text-secondary));
    margin-block-start: var(--awx-space-heading-above);
    margin-block-end: var(--awx-space-heading-below);
  }


  //** ── Paragraphs & Inline ─────────────────────────────────────────────── **//

  :where(.entry-content) p {
    font-size: var(--awx-font-size-0);
    line-height: var(--awx-leading-relaxed);
    color: hsl(var(--awx-color-on-background));
    max-width: var(--awx-width-measure);
  }

  :where(.entry-content) h1 + p,
  :where(.entry-content) .is-style-lead {
    font-size: var(--awx-font-size-1);
    line-height: var(--awx-leading-relaxed);
    color: hsl(var(--awx-color-text-secondary));
    max-width: var(--awx-width-measure-wide);
  }

  :where(.entry-content) strong,
  :where(.entry-content) b {
    font-weight: var(--awx-font-weight-semibold);
    color: hsl(var(--awx-color-text));
  }

  :where(.entry-content) em,
  :where(.entry-content) i {
    font-style: italic;
  }

  :where(.entry-content) small {
    font-size: var(--awx-font-size--1);
  }

  :where(.entry-content) mark {
    background-color: hsl(var(--awx-color-warning-light));
    color: hsl(var(--awx-color-text));
    padding-inline: 0.2em;
    border-radius: var(--awx-radius-sm);
  }

  :where(.entry-content) abbr[title] {
    text-decoration: underline dotted;
    cursor: help;
  }

  :where(.entry-content) sup,
  :where(.entry-content) sub {
    font-size: var(--awx-font-size--2);
    line-height: 0;
    position: relative;
    vertical-align: baseline;
  }

  :where(.entry-content) sup { top: -0.5em; }
  :where(.entry-content) sub { bottom: -0.25em; }


  //** ── Links ───────────────────────────────────────────────────────────── **//

  :where(.entry-content) a {
    color: hsl(var(--awx-color-link));
    text-decoration: underline;
    text-decoration-color: hsl(var(--awx-color-link) / 0.4);
    text-underline-offset: 0.15em;
    text-decoration-thickness: 1px;
    transition: color var(--awx-duration-fast) var(--awx-ease-standard),
                text-decoration-color var(--awx-duration-fast) var(--awx-ease-standard);
  }

  :where(.entry-content) a:hover {
    color: hsl(var(--awx-color-link-hover));
    text-decoration-color: hsl(var(--awx-color-link-hover));
  }

  :where(.entry-content) a:visited {
    color: hsl(var(--awx-color-link-visited));
  }


  //** ── Lists ───────────────────────────────────────────────────────────── **//

  :where(.entry-content) ul,
  :where(.entry-content) ol {
    padding-inline-start: var(--awx-space-4);
    max-width: var(--awx-width-measure);
  }

  :where(.entry-content) li {
    line-height: var(--awx-leading-relaxed);
  }

  :where(.entry-content) li + li {
    margin-block-start: var(--awx-space-05);
  }

  :where(.entry-content) li > ul,
  :where(.entry-content) li > ol {
    margin-block-start: var(--awx-space-05);
  }

  :where(.entry-content) ul { list-style-type: disc; }
  :where(.entry-content) ul ul { list-style-type: circle; }
  :where(.entry-content) ul ul ul { list-style-type: square; }
  :where(.entry-content) ol { list-style-type: decimal; }


  //** ── Blockquotes ─────────────────────────────────────────────────────── **//

  :where(.entry-content) blockquote {
    border-inline-start: 4px solid hsl(var(--awx-color-primary));
    padding-inline-start: var(--awx-space-3);
    padding-block: var(--awx-space-1);
    margin-inline: 0;
    max-width: var(--awx-width-measure);
  }

  :where(.entry-content) blockquote p {
    font-size: var(--awx-font-size-1);
    font-style: italic;
    line-height: var(--awx-leading-relaxed);
    color: hsl(var(--awx-color-text-secondary));
  }

  :where(.entry-content) blockquote cite,
  :where(.entry-content) blockquote footer {
    display: block;
    font-size: var(--awx-font-size--1);
    font-style: normal;
    font-weight: var(--awx-font-weight-medium);
    color: hsl(var(--awx-color-text-muted));
    margin-block-start: var(--awx-space-1);
  }

  :where(.entry-content) blockquote cite::before {
    content: "— ";
  }


  //** ── Code ────────────────────────────────────────────────────────────── **//

  :where(.entry-content) code {
    font-family: var(--awx-font-mono);
    font-size: 0.875em;
    background-color: hsl(var(--awx-color-surface));
    color: hsl(var(--awx-color-text));
    padding: 0.15em 0.35em;
    border-radius: var(--awx-radius-sm);
    border: var(--awx-border-thin) solid hsl(var(--awx-color-border));
  }

  :where(.entry-content) pre {
    font-family: var(--awx-font-mono);
    font-size: var(--awx-font-size--1);
    line-height: var(--awx-leading-relaxed);
    background-color: hsl(var(--awx-neutral-900));
    color: hsl(var(--awx-neutral-100));
    padding: var(--awx-space-3);
    border-radius: var(--awx-radius-md);
    overflow-x: auto;
    tab-size: 2;
    max-width: 100%;
  }

  :where(.entry-content) pre code {
    background: none;
    border: none;
    padding: 0;
    font-size: inherit;
    color: inherit;
    border-radius: 0;
  }

  :where(.entry-content) kbd {
    font-family: var(--awx-font-mono);
    font-size: 0.875em;
    background-color: hsl(var(--awx-color-surface));
    border: var(--awx-border-thin) solid hsl(var(--awx-color-border-strong));
    border-radius: var(--awx-radius-sm);
    padding: 0.1em 0.35em;
    box-shadow: 0 1px 0 hsl(var(--awx-color-border-strong));
  }


  //** ── Tables ──────────────────────────────────────────────────────────── **//

  :where(.entry-content) table {
    width: 100%;
    font-size: var(--awx-font-size--1);
    line-height: var(--awx-leading-normal);
    text-align: start;
  }

  :where(.entry-content) thead {
    border-block-end: 2px solid hsl(var(--awx-color-border-strong));
  }

  :where(.entry-content) th {
    font-weight: var(--awx-font-weight-semibold);
    color: hsl(var(--awx-color-text));
    padding: var(--awx-space-15) var(--awx-space-2);
    text-align: inherit;
  }

  :where(.entry-content) td {
    padding: var(--awx-space-15) var(--awx-space-2);
    color: hsl(var(--awx-color-on-surface));
    border-block-end: var(--awx-border-thin) solid hsl(var(--awx-color-divider));
  }

  :where(.entry-content) tbody tr:last-child td {
    border-block-end: none;
  }

  :where(.entry-content) caption {
    font-size: var(--awx-font-size--1);
    color: hsl(var(--awx-color-text-muted));
    padding-block: var(--awx-space-1);
    caption-side: bottom;
    text-align: start;
  }


 //** ── Images & Figures ────────────────────────────────────────────────── **//

  :where(.entry-content) figure {
    margin-inline: 0;
  }

  :where(.entry-content) figure img {
    border-radius: var(--awx-radius-md);
  }

  :where(.entry-content) figcaption {
    font-size: var(--awx-font-size--1);
    line-height: var(--awx-leading-normal);
    color: hsl(var(--awx-color-text-muted));
    margin-block-start: var(--awx-space-1);
    text-align: center;
  }


  //** ── Horizontal Rules ────────────────────────────────────────────────── **//

  :where(.entry-content) hr {
    border: none;
    border-block-start: var(--awx-border-thin) solid hsl(var(--awx-color-divider));
    margin-block: var(--awx-space-6);
  }


  //** ── Definition Lists ────────────────────────────────────────────────── **//

  :where(.entry-content) dl {
    max-width: var(--awx-width-measure);
  }

  :where(.entry-content) dt {
    font-weight: var(--awx-font-weight-semibold);
    color: hsl(var(--awx-color-text));
    margin-block-start: var(--awx-space-2);
  }

  :where(.entry-content) dt:first-child {
    margin-block-start: 0;
  }

  :where(.entry-content) dd {
    margin-inline-start: var(--awx-space-4);
    color: hsl(var(--awx-color-on-surface));
  }


  //** ── Details / Summary ───────────────────────────────────────────────── **//

  :where(.entry-content) details {
    border: var(--awx-border-thin) solid hsl(var(--awx-color-border));
    border-radius: var(--awx-radius-md);
    padding: var(--awx-space-2) var(--awx-space-3);
  }

  :where(.entry-content) summary {
    font-weight: var(--awx-font-weight-medium);
    color: hsl(var(--awx-color-text));
    cursor: pointer;
    list-style: none;
  }

  :where(.entry-content) summary::-webkit-details-marker {
    display: none;
  }

  :where(.entry-content) summary::before {
    content: "▸ ";
    display: inline-block;
    transition: transform var(--awx-duration-fast) var(--awx-ease-standard);
  }

  :where(.entry-content) details[open] summary::before {
    transform: rotate(90deg);
  }

  :where(.entry-content) details > *:not(summary) {
    margin-block-start: var(--awx-space-2);
  }


  //** ── Embedded Content ────────────────────────────────────────────────── **//

  :where(.entry-content) iframe {
    max-width: 100%;
    border: none;
  }

  :where(.entry-content) video {
    max-width: 100%;
    height: auto;
  }


  //** ── Address ─────────────────────────────────────────────────────────── **//

  :where(.entry-content) address {
    font-style: normal;
    line-height: var(--awx-leading-relaxed);
  }

}

//**
 * Awesome CSS — Reset v0.1.0
 *
 * Minimal modern reset inside @layer base. Global (not scoped).
 * Removes inconsistencies, sets sensible defaults, preserves useful ones.
 **//

@layer base {

  *,
  *::before,
  *::after {
    box-sizing: border-box;
  }

  body,
  h1, h2, h3, h4, h5, h6,
  p, figure, blockquote,
  dl, dd, pre {
    margin: 0;
  }

  html {
    -webkit-text-size-adjust: 100%;
    text-size-adjust: 100%;
    tab-size: 4;
    line-height: 1.5;
  }

  body {
    min-height: 100dvh;
    font-family: var(--awx-font-body);
    font-size: var(--awx-font-size-0);
    line-height: var(--awx-leading-normal);
    color: hsl(var(--awx-color-text));
    background-color: hsl(var(--awx-color-background));
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  img, picture, video, canvas, svg {
    display: block;
    max-width: 100%;
    height: auto;
  }

  input, button, textarea, select {
    font: inherit;
    color: inherit;
  }

  h1, h2, h3, h4, h5, h6 {
    overflow-wrap: break-word;
    text-wrap: balance;
  }

  p {
    overflow-wrap: break-word;
    text-wrap: pretty;
  }

  button {
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
  }

  a {
    color: inherit;
    text-decoration: inherit;
  }

  table {
    border-collapse: collapse;
    border-spacing: 0;
  }

  @media (prefers-reduced-motion: reduce) {
    *, *::before, *::after {
      animation-duration: 0.01ms !important;
      animation-iteration-count: 1 !important;
      transition-duration: 0.01ms !important;
      scroll-behavior: auto !important;
    }
  }

  :focus-visible {
    outline: 2px solid hsl(var(--awx-color-focus-ring));
    outline-offset: 2px;
  }

  :focus:not(:focus-visible) {
    outline: none;
  }

  ::selection {
    background-color: hsl(var(--awx-color-primary) / 0.15);
    color: hsl(var(--awx-color-text));
  }

}

